// Evento de detección → formato InfluxDB
const d = msg.payload;

msg.payload = [{
    measurement: 'animal_detections',
    tags: {
        camera_id: d.camera_id || 'unknown',
        farm_id: d.farm_id || 'unknown'
    },
    fields: {
        n_detections: d.n_detections || 0,
        inference_ms: d.inference_ms || 0,
        event_id: d.event_id || ''
    },
    timestamp: new Date(d.timestamp || Date.now())
}];

// Añadir conteos por especie
const species = d.species_counts || {};
for (const [sp, count] of Object.entries(species)) {
    msg.payload.push({
        measurement: 'species_counts',
        tags: {
            camera_id: d.camera_id || 'unknown',
            farm_id: d.farm_id || 'unknown',
            species: sp
        },
        fields: {
            count: count
        },
        timestamp: new Date(d.timestamp || Date.now())
    });
}

return msg;

// Evento de peso → formato InfluxDB
const d = msg.payload;

msg.payload = [{
    measurement: 'weight_estimates',
    tags: {
        camera_id: d.camera_id || 'unknown',
        farm_id: d.farm_id || 'unknown',
        species: d.species || 'unknown',
        calibrated: String(d.calibrated || false)
    },
    fields: {
        weight_kg: d.weight_kg || 0,
        confidence: d.confidence || 0
    },
    timestamp: new Date(d.timestamp || Date.now())
}];

return msg;

// Alerta de comportamiento → formato InfluxDB
const d = msg.payload;

msg.payload = [{
    measurement: 'behaviour_alerts',
    tags: {
        camera_id: d.camera_id || 'unknown',
        farm_id: d.farm_id || 'unknown',
        species: d.species || 'unknown',
        behaviour: d.behaviour || 'unknown',
        severity: d.severity || 'info'
    },
    fields: {
        confidence: d.confidence || 0,
        duration_s: d.duration_s || 0,
        alert_id: d.alert_id || ''
    },
    timestamp: new Date(d.timestamp || Date.now())
}];

// Alerta crítica → Telegram
if (d.severity === 'alert') {
    const teleMsg = {
        payload: `🚨 ALERTA VISION\n` +
                 `Cámara: ${d.camera_id}\n` +
                 `Granja: ${d.farm_id}\n` +
                 `Comportamiento: ${d.behaviour}\n` +
                 `Especie: ${d.species}\n` +
                 `Confianza: ${(d.confidence * 100).toFixed(0)}%\n` +
                 `Duración: ${d.duration_s}s`
    };
    node.send([msg, teleMsg]);
    return;
}

return [msg, null];

// Preparar para nodo Telegram o HTTP POST
const text = msg.payload;
msg.payload = {
    chatId: env.get('TELEGRAM_CHAT_ID'),
    type: 'message',
    content: text
};
return msg;

// Cada 5 minutos: consulta las últimas detecciones y agrega
// En producción, esto consulta InfluxDB directamente
const now = new Date();
const fiveMinAgo = new Date(now - 5 * 60 * 1000);

msg.payload = [{
    measurement: 'vision_heartbeat',
    tags: {
        service: 'nodered-vision'
    },
    fields: {
        status: 1,
        uptime_s: Math.floor(process.uptime())
    },
    timestamp: now
}];

return msg;
